import pandas as pd
from sklearn.preprocessing import MinMaxScaler

def task_func(file_name: str) -> tuple[pd.DataFrame]:
    try:
        # Load the data
        df = pd.read_csv(file_name)

        # Check if there are numeric columns
        if not df.select_dtypes(include=['int64', 'float64']).empty:
            # Initialize MinMaxScaler
            scaler = MinMaxScaler()

            # Normalize the data
            df_num = df.select_dtypes(include=['int64', 'float64'])
            df_num = pd.DataFrame(scaler.fit_transform(df_num), columns=df_num.columns)
            df = df.join(df_num)
        else:
            raise ValueError("Input does not have numeric columns.")

        return (df, )
    except Exception as e:
        print(f"Error occurred: {e}")
        return None
